// Multi-brand prefix routing for UGC ingest.
// Filenames must follow: <PREFIX>_<description>.<ext>
// Files without a recognized prefix are flagged skip:true and routed to Quarantine.
const items = $input.all();
const results = [];

const BRAND_MAP = {
  'EF': 'effecto',
  'LC': 'lastingchange',
  'WB': 'welcomebaby',
  'ND': 'nodiet',
  'CL': 'cyclediet',
  'HD': 'highdiet',
  'LD': 'lastdiet',
  'BW': 'brainway',
  'WY': 'walkingyoga',
  'GD': 'greendiet',
  'NH': 'novahealth',
  'MG': 'moongrade',
  'OD': 'offdiet',
  'AT': 'airdiet',
  'CM': 'carnimeat',
  'NY': 'nordyoga',
  'NP': 'nordpilates',
  'CD': 'cyclediet',
  'NM': 'nomorediet',
  'KD': 'ketoway',
  'HY': 'harmonydiet',
  'KY': 'koiyoga',
  'ML': 'menletics',
  'RD': 'raisingdog',
  'MW': 'mindway',
  'NA': 'nordastro',
  'NL': 'nordletics',
  'MP': 'manifestationparadox',
  'GL': 'glpdiet',
  'CX': 'cortisoldetox',
  'TA': 'taiyoga',
  'FD': 'flamediet',
  'LX': 'liverdetox'
};

for (const item of items) {
  const name = item.json.name || Object.keys(item.binary || {})[0] || 'unknown.mp4';
  const sanitized = name.replace(/[^a-zA-Z0-9._-]/g, '_');
  const nameWithoutExt = sanitized.replace(/\.[^.]+$/, '');
  const underscoreIdx = nameWithoutExt.indexOf('_');

  let brandId = null;
  let description = '';
  let skip = false;
  let reason = '';

  if (underscoreIdx <= 0) {
    skip = true;
    reason = 'no_prefix_underscore';
  } else {
    const prefix = nameWithoutExt.slice(0, underscoreIdx);
    if (!Object.prototype.hasOwnProperty.call(BRAND_MAP, prefix)) {
      skip = true;
      reason = 'unknown_prefix:' + prefix;
    } else {
      brandId = BRAND_MAP[prefix];
      description = nameWithoutExt.slice(underscoreIdx + 1);
    }
  }

  results.push({
    json: {
      driveFileId: item.json.id || '',
      driveName: name,
      sanitizedName: sanitized,
      brandId: brandId,
      description: description,
      skip: skip,
      reason: reason,
      timestamp: new Date().toISOString()
    },
    binary: item.binary
  });
}

return results;
